import{v as n}from"./chunks/variables.D84Etxxq.js";import{I as r,c as s,o as d,ah as o,j as t,a,k as h,J as l}from"./chunks/framework.BwTf_eGd.js";const c="/assets/integrations_youtube-music-export-cookies.DtJfWvL3.png",u=["href"],p={id:"youtube-music",tabindex:"-1"},g={id:"jellyfin-push",tabindex:"-1"},w=JSON.parse('{"title":"Integrations","description":"","frontmatter":{},"headers":[],"relativePath":"integrations.md","filePath":"integrations.md","lastUpdated":1747795404000}'),m={name:"integrations.md"},v=Object.assign(m,{setup(b){return(f,e)=>{const i=r("Badge");return d(),s("div",null,[e[13]||(e[13]=o(`<h1 id="integrations" tabindex="-1">Integrations <a class="header-anchor" href="#integrations" aria-label="Permalink to “Integrations”">​</a></h1><p>Integrations can be used to continuously update your media progress or inform external services about changes. They can be of following types:</p><ul><li><em>Sink</em>: An external client publishes progress updates to the Ryot server.</li><li><em>Yank</em>: Progress data is downloaded from an externally running server at a periodic interval.</li><li><em>Push</em>: Ryot sends data to an external service when an event occurs.</li></ul><p>If an integration fails more than 5 times in a row, it will be automatically paused. This behavior can be disabled from the integration&#39;s settings.</p><h2 id="sink-integrations" tabindex="-1">Sink integrations <a class="header-anchor" href="#sink-integrations" aria-label="Permalink to “Sink integrations”">​</a></h2><p>These work via webhooks wherein an external service can inform Ryot about a change. All webhook URLs follow this format:</p><div class="language-txt"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>https://&lt;instance_url&gt;/backend/_i/&lt;slug&gt;</span></span>
<span class="line"><span>https://app.ryot.io/backend/_i/int_a6cGGXEq6KOI # example</span></span></code></pre></div><div class="warning custom-block"><p class="custom-block-title custom-block-title-default">WARNING</p><p>Keep your webhook urls private to prevent abuse.</p></div><h3 id="jellyfin-sink" tabindex="-1">Jellyfin Sink <a class="header-anchor" href="#jellyfin-sink" aria-label="Permalink to “Jellyfin Sink”">​</a></h3><p>Automatically add new <a href="https://jellyfin.org/" target="_blank" rel="noreferrer">Jellyin</a> movie and show plays to Ryot. It will work for all the media that have a valid TMDb ID attached to their metadata.</p><div class="info custom-block"><p class="custom-block-title custom-block-title-default">INFO</p><p>Requires the <a href="https://github.com/shemanaev/jellyfin-plugin-webhooks" target="_blank" rel="noreferrer">unofficial webhook plugin</a> to be installed and active in Jellyfin.</p></div><ol><li>Generate a slug in the integration settings page. Copy the newly generated webhook Url.</li><li>In the Jellyfin webhook plugin settings, add a new webhook using the following settings: <ul><li>Webhook Url =&gt; <code>&lt;paste_url_copied&gt;</code></li><li>Payload format =&gt; <code>Default</code></li><li>Listen to events only for =&gt; Choose your user</li><li>Events =&gt; <code>Play</code>, <code>Pause</code>, <code>Resume</code>, <code>Stop</code>, <code>Progress</code> and <code>MarkPlayed</code></li></ul></li></ol><h3 id="emby" tabindex="-1">Emby <a class="header-anchor" href="#emby" aria-label="Permalink to “Emby”">​</a></h3><p>Automatically add new <a href="https://emby.media/" target="_blank" rel="noreferrer">Emby</a> movie and show plays to Ryot. It will work for all the media that have a valid TMDb ID attached to their metadata.</p><ol><li>Generate a slug in the integration settings page. Copy the newly generated webhook Url.</li><li>In the Emby notification settings page, add a new notification using the Webhooks option: <ul><li>Name =&gt; <code>ryot</code></li><li>Url =&gt; <code>&lt;paste_url_copied&gt;</code></li><li>Request Content Type =&gt; <code>application/json</code></li><li>Events =&gt; <code>Play</code>, <code>Pause</code>, <code>Resume</code>, <code>Stop</code> and <code>Progress</code></li><li>Limit user events to =&gt; Choose your user</li></ul></li></ol><div class="warning custom-block"><p class="custom-block-title custom-block-title-default">WARNING</p><p>Since Emby does not send the expected TMDb ID for shows, progress will only be synced if you already have the show in the Ryot database. To do this, simply add the show to your watchlist.</p></div><h3 id="plex-sink" tabindex="-1">Plex Sink <a class="header-anchor" href="#plex-sink" aria-label="Permalink to “Plex Sink”">​</a></h3><div class="info custom-block"><p class="custom-block-title custom-block-title-default">INFO</p><p>This will only import media that are in progress. Perform an <a href="./importing/plex.html">import</a> if you want to import media that are finished.</p></div><p>Automatically add <a href="https://www.plex.tv/" target="_blank" rel="noreferrer">Plex</a> show and movie plays to Ryot. It will work for all the media that have a valid TMDb ID attached to their metadata.</p><ol><li>Generate a slug in the integration settings page using the following settings: <ul><li>Username =&gt; Your Plex <code>Fullname</code>. If you have no <code>Fullname</code> specified in Plex, fallback to your Plex <code>Username</code>. This will be used to filter webhooks for the specified Plex account only.</li></ul></li><li>In your Plex Webhooks settings, add a new webhook using the following settings: <ul><li>Webhook Url =&gt; <code>&lt;paste_url_copied&gt;</code></li></ul></li></ol><div class="warning custom-block"><p class="custom-block-title custom-block-title-default">WARNING</p><p>Since Plex does not send the expected TMDb ID for shows, progress will only be synced if you already have the show in the Ryot database. To do this, simply add the show to your watchlist.</p></div><h3 id="kodi" tabindex="-1">Kodi <a class="header-anchor" href="#kodi" aria-label="Permalink to “Kodi”">​</a></h3><p>The <a href="https://kodi.tv/" target="_blank" rel="noreferrer">Kodi</a> integration allows syncing the current movie or TV show you are watching. It will work for all the media that have a valid TMDb ID attached to their metadata.</p>`,23)),t("ol",null,[e[4]||(e[4]=t("li",null,"Generate a slug in the integration settings page. Copy the newly generated webhook Url.",-1)),t("li",null,[e[0]||(e[0]=a("Download the addon from ")),t("a",{href:`${h(n).repoUrl}/releases`,target:"_blank"},"github releases",8,u),e[1]||(e[1]=a(". The file will have a name of ")),e[2]||(e[2]=t("code",null,"script.ryot.zip",-1)),e[3]||(e[3]=a("."))]),e[5]||(e[5]=t("li",null,[t("a",{href:"https://kodi.wiki/view/Add-on_manager#How_to_install_from_a_ZIP_file",target:"_blank",rel:"noreferrer"},"Install"),a(' the zipped addon to your Kodi instance. Once installed, it will be visible under the "Services" sub category named "Ryot".')],-1)),e[6]||(e[6]=t("li",null,'Click on "Configure" to fill in the correct details.',-1))]),e[14]||(e[14]=o('<h3 id="generic-json" tabindex="-1">Generic Json <a class="header-anchor" href="#generic-json" aria-label="Permalink to “Generic Json”">​</a></h3><p>The &quot;Generic Json&quot; can be used to import all possible data using a generic JSON data format. The format of the JSON file should be <code>CompleteExport</code> as described in the <a href="./guides/exporting.html#type-definitions">exporting</a> documentation.</p><p>You can use this to build integrations with other services that Ryot does not support natively.</p><h2 id="yank-integrations" tabindex="-1">Yank integrations <a class="header-anchor" href="#yank-integrations" aria-label="Permalink to “Yank integrations”">​</a></h2><p>You can configure the interval at which the data is fetched from the external source using the <code>INTEGRATION_SYNC_EVERY_MINUTES</code> environment variable. Defaults to <code>5</code>.</p><p>If you have enabled the <code>Sync to owned collection</code> option, the integration will also run at night to add all media in your instance to your &quot;Owned&quot; collection.</p><h3 id="audiobookshelf" tabindex="-1">Audiobookshelf <a class="header-anchor" href="#audiobookshelf" aria-label="Permalink to “Audiobookshelf”">​</a></h3><div class="info custom-block"><p class="custom-block-title custom-block-title-default">INFO</p><p>This will only import media that are in progress. Perform an <a href="./importing/audiobookshelf.html">import</a> if you want to import media that are finished.</p></div><p>The <a href="https://www.audiobookshelf.org" target="_blank" rel="noreferrer">Audiobookshelf</a> integration can sync all media if they have a valid provider ID (Audible, ITunes or ISBN).</p><ol><li>Obtain an API token as described in the Audiobookshelf <a href="https://api.audiobookshelf.org/#authentication" target="_blank" rel="noreferrer">authentication</a> docs.</li><li>Go to your Ryot integrations settings and add the correct details as described in the <a href="#yank-integrations">yank</a> section.</li></ol><h3 id="komga" tabindex="-1">Komga <a class="header-anchor" href="#komga" aria-label="Permalink to “Komga”">​</a></h3><p>The <a href="https://komga.org/" target="_blank" rel="noreferrer">Komga</a> integration can sync all media if they have a valid metadata provider. If you use <a href="https://github.com/Snd-R/komf" target="_blank" rel="noreferrer">Komf</a> or some similar metadata provider these urls will be populated automatically. If you don&#39;t, you will either need to manually add the manga to your collection or you can perform the following steps.</p><ol><li>Navigate to the manga and open the Edit tab</li><li>Navigate to the Links tab</li><li>Create a link named <code>AniList</code> or <code>MyAnimeList</code> providing the respective url (not case-sensitive)</li><li>On Ryot, create an integration and select Komga as the source</li><li>Provide your Base URL. It should look something like this <code>https://komga.acme.com</code> or <code>http://127.0.0.1:25600</code></li><li>Provide your Username and Password.</li><li>Provide your preferred metadata provider. Ryot will attempt the others if the preferred is unavailable and will fallback to title search otherwise.</li></ol><h3 id="plex-yank" tabindex="-1">Plex Yank <a class="header-anchor" href="#plex-yank" aria-label="Permalink to “Plex Yank”">​</a></h3><p>This integration will add all media in your libraries to the &quot;Owned&quot; collection. If you want to sync media progress, then take a look at the <a href="#plex-sink">Plex Sink</a> integration.</p><ol><li>Get the Plex token. If you want to import data for an admin account, then you need a <a href="https://www.plexopedia.com/plex-media-server/general/plex-token/#devicetoken" target="_blank" rel="noreferrer">device token</a>. Otherwise, a current <a href="https://www.plexopedia.com/plex-media-server/general/plex-token/#getcurrentusertoken" target="_blank" rel="noreferrer">user token</a> is sufficient.</li><li>Go to your Ryot integration settings and fill in the details.</li></ol>',16)),t("h3",p,[e[7]||(e[7]=a("Youtube Music ")),l(i,{type:"warning",text:"PRO"}),e[8]||(e[8]=a()),e[9]||(e[9]=t("a",{class:"header-anchor",href:"#youtube-music","aria-label":"Permalink to “Youtube Music”"},"​",-1))]),e[15]||(e[15]=o('<p>The <a href="https://music.youtube.com" target="_blank" rel="noreferrer">Youtube Music</a> integration syncs all music that you have listened to <a href="https://music.youtube.com/history" target="_blank" rel="noreferrer">&quot;Today&quot;</a>. Since Youtube Music does not have an official API, this integration is prone to breakage and needs some roundabout steps to setup.</p><ol><li>Install the <a href="https://cookie-editor.com" target="_blank" rel="noreferrer">Cookie Editor</a> extension in your browser. Make sure you allow the extension to work on incognito windows.</li><li>Open a new incognito window in your browser and login to Youtube Music.</li><li>Once logged in, open the extension and export the cookies as &quot;Header String&quot;. After copying them, close the incognito browser immediately so that they are not invalidated. <img src="'+c+'" alt="image"></li><li>Paste the exported cookies in the input.</li></ol><h2 id="push-integrations" tabindex="-1">Push integrations <a class="header-anchor" href="#push-integrations" aria-label="Permalink to “Push integrations”">​</a></h2><p>You can enable the following push integrations:</p><h3 id="radarr" tabindex="-1">Radarr <a class="header-anchor" href="#radarr" aria-label="Permalink to “Radarr”">​</a></h3><p>Events: <code>Item added to collection</code></p><ol><li>Obtain your Radarr API key by going to the Radarr general settings page.</li><li>Fill the inputs in the integration settings page with the correct details.</li></ol><h3 id="sonarr" tabindex="-1">Sonarr <a class="header-anchor" href="#sonarr" aria-label="Permalink to “Sonarr”">​</a></h3><p>Events: <code>Item added to collection</code></p><ol><li>Obtain your Sonarr API key by going to the Sonarr general settings page.</li><li>Fill the inputs in the integration settings page with the correct details.</li></ol>',10)),t("h3",g,[e[10]||(e[10]=a("Jellyfin Push ")),l(i,{type:"warning",text:"PRO"}),e[11]||(e[11]=a()),e[12]||(e[12]=t("a",{class:"header-anchor",href:"#jellyfin-push","aria-label":"Permalink to “Jellyfin Push”"},"​",-1))]),e[16]||(e[16]=t("p",null,[a("Events: "),t("code",null,"Item marked as completed")],-1)),e[17]||(e[17]=t("ol",null,[t("li",null,"While creating the integration, you will be asked to provide your Jellyfin username and password."),t("li",null,"Every time you mark a movie or show as watched in Ryot, the integration will mark it as watched in Jellyfin.")],-1))])}}});export{w as __pageData,v as default};
